return ['domain'=>'magicauth','plural-forms'=>'nplurals=2; plural=(n != 1);','language'=>'es_ES','project-id-version'=>'MagicAuth 1.0.3','pot-creation-date'=>'2026-05-22T19:10:14+00:00','po-revision-date'=>'2026-05-22','x-generator'=>'MagicAuth i18n generator','messages'=>['Passwordless WordPress sign-in via email magic link or 6-character code.'=>'Inicio de sesión en WordPress sin contraseña mediante enlace mágico por correo o código de 6 caracteres.','MagicAuth by Ettic.'=>'MagicAuth de Ettic.','Focused, open-source WordPress plugins.'=>'Plugins de WordPress enfocados y de código abierto.','MagicAuth resources'=>'Recursos de MagicAuth','Docs'=>'Documentación','Support'=>'Soporte','Report a vulnerability'=>'Informar de una vulnerabilidad','Like MagicAuth? Leave a review and help us keep building open source.'=>'¿Le gusta MagicAuth? Deje una reseña y ayúdenos a seguir creando código abierto.','Leave a review'=>'Dejar una reseña','Settings'=>'Ajustes','Discard'=>'Descartar','Save changes'=>'Guardar cambios','Passwordless sign-in via magic link or 6-character code. Configure how it looks, how it behaves, and how it recovers from edge cases. All on one page.'=>'Inicio de sesión sin contraseña mediante enlace mágico o código de 6 caracteres. Configure su aspecto, su comportamiento y cómo se recupera de casos límite. Todo en una sola página.','General'=>'General','How long links live and where users land afterwards.'=>'Cuánto tiempo viven los enlaces y dónde aterrizan los usuarios después.','Branding'=>'Personalización de marca','How the sign-in card looks. Settings render on the branded login screen and in transactional emails.'=>'Aspecto de la tarjeta de inicio de sesión. Estos ajustes se aplican en la pantalla de acceso personalizada y en los correos transaccionales.','Agency credit'=>'Crédito de agencia','Optional "Built by [Brand]" line below the sign-in card. Renders only when name, URL, and favicon are all filled.'=>'Línea opcional "Creado por [Marca]" debajo de la tarjeta de inicio de sesión. Solo se muestra cuando el nombre, la URL y el favicon están todos rellenados.','Security &amp; throttling'=>'Seguridad &amp; limitación','Recovery layers and rate-limit caps. The "Sign in with password" link is the unconditional safety net. Disable it only after site-wide password auth is already off.'=>'Capas de recuperación y límites de frecuencia. El enlace "Iniciar sesión con contraseña" es la red de seguridad incondicional. Desactívelo solo después de haber desactivado la autenticación por contraseña en todo el sitio.','Diagnostics &amp; recovery'=>'Diagnóstico &amp; recuperación','One-shot tools for debugging and unsticking the plugin. Destructive actions ask for confirmation.'=>'Herramientas de un solo uso para depurar y desbloquear el plugin. Las acciones destructivas piden confirmación.','Send test email'=>'Enviar correo de prueba','One-shot diagnostic. No tokens are issued. Forces the default brand color to verify rendering.'=>'Diagnóstico de un solo uso. No se emiten tokens. Fuerza el color de marca predeterminado para verificar la representación.','Send to my account'=>'Enviar a mi cuenta','Revoke all magic-links and codes'=>'Revocar todos los enlaces mágicos y códigos','Marks every unconsumed token consumed site-wide. Already-active sessions are not signed out.'=>'Marca como usado cada token sin consumir en todo el sitio. Las sesiones ya activas no se cierran.','Revoke now'=>'Revocar ahora','Reset throttle counters'=>'Restablecer contadores de límite','Deletes every magicauth_throttle_* transient. Object-cache safe.'=>'Elimina cada transient magicauth_throttle_*. Seguro para la caché de objetos.','Reset now'=>'Restablecer ahora','Branded login is enabled, but your WordPress salts are still weak. Magic links each carry their own random secret so they stay safe; your session cookies and the 6-character codes are better protected once you fix the salts. See the weak-salt notice for how.'=>'El inicio de sesión personalizado está activado, pero las salts de WordPress aún son débiles. Cada enlace mágico lleva su propio secreto aleatorio, por lo que permanecen seguros; las cookies de sesión y los códigos de 6 caracteres estarán mejor protegidos en cuanto corrija las salts. Consulte el aviso de salts débiles para saber cómo.','Sender address: that value had no usable characters, so it was reset to "login".'=>'Dirección del remitente: ese valor no tenía caracteres utilizables, por lo que se restableció a "login".','Logo: selected attachment is not an image.'=>'Logo: el archivo seleccionado no es una imagen.','Logo: SVG contains active content (script / event handlers / javascript:). Re-export without scripting.'=>'Logo: el SVG contiene contenido activo (script / controladores de eventos / javascript:). Vuelva a exportarlo sin scripting.','Logo: only PNG, JPG, WebP, or SVG are allowed.'=>'Logo: solo se permiten PNG, JPG, WebP o SVG.','Logo: file content does not match a supported image format.'=>'Logo: el contenido del archivo no coincide con un formato de imagen compatible.','Link &amp; code lifetime'=>'Duración del enlace &amp; código','Both the magic link and the typeable code share one expiry. Range 1–30 minutes.'=>'El enlace mágico y el código tecleable comparten un mismo vencimiento. Rango de 1–30 minutos.','minutes'=>'minutos','Max link uses'=>'Usos máximos del enlace','2 absorbs URL-scanner prefetch plus the user\'s click. Set to 1 for strict single-use.'=>'2 absorbe la precarga de los escáneres de URL más el clic del usuario. Establezca 1 para un uso único estricto.','Auto (admin or home, by capability)'=>'Automático (administración o inicio, según permisos)','Site home'=>'Inicio del sitio','Admin dashboard'=>'Escritorio de administración','Default redirect after sign-in'=>'Redirección predeterminada tras iniciar sesión','Where users land when no specific destination was requested.'=>'Dónde aterrizan los usuarios cuando no se solicitó un destino específico.','Replace WordPress login screen'=>'Reemplazar la pantalla de acceso de WordPress','Why is this flagged?'=>'¿Por qué se marca esto?','Heads up: weak salts'=>'Atención: salts débiles','You can turn this on now, but the salts in'=>'Puede activarlo ahora, pero las salts en','are weak — fixing them first is recommended.'=>'son débiles — se recomienda corregirlas primero.','How to fix →'=>'Cómo corregirlo →','Intercepts wp-login.php and serves the branded MagicAuth screen. The native form stays available at ?magicauth=off as a recovery path.'=>'Intercepta wp-login.php y muestra la pantalla personalizada de MagicAuth. El formulario nativo sigue disponible en ?magicauth=off como vía de recuperación.','Hide language switcher'=>'Ocultar el selector de idioma','WordPress adds a language selector to the login screen when extra languages are installed. MagicAuth places it under the card. Turn this on to hide it on the branded screen; the recovery login at ?magicauth=off keeps it.'=>'WordPress añade un selector de idioma a la pantalla de acceso cuando hay idiomas adicionales instalados. MagicAuth lo coloca bajo la tarjeta. Active esto para ocultarlo en la pantalla personalizada; el acceso de recuperación en ?magicauth=off lo conserva.','Company name'=>'Nombre de la empresa','Your short business name. No taglines, slogans, or separators.'=>'El nombre corto de su empresa. Sin lemas, eslóganes ni separadores.','Sender email address'=>'Dirección de correo del remitente','The address sign-in emails are sent from. Only the part before the @ is editable — it stays on your own domain so messages pass spam checks (SPF/DKIM/DMARC) instead of being flagged as forged. Letters, digits, and . _ - + only.'=>'La dirección desde la que se envían los correos de acceso. Solo se puede editar la parte anterior a la @ — permanece en su propio dominio para que los mensajes superen las comprobaciones antispam (SPF/DKIM/DMARC) en lugar de marcarse como falsificados. Solo letras, dígitos y . _ - +.','PNG, JPG, or WebP. Existing SVG attachments may also be selected. Capped at 48px height on the sign-in card.'=>'PNG, JPG o WebP. También pueden seleccionarse archivos SVG existentes. Limitado a 48px de altura en la tarjeta de inicio de sesión.','Brand color'=>'Color de marca','Auto-derives readable button text via YIQ luminance. Current contrast:'=>'Deriva automáticamente un texto de botón legible mediante luminancia YIQ. Contraste actual:','Color picker'=>'Selector de color','Brand name'=>'Nombre de marca','Shown bold in the credit line.'=>'Se muestra en negrita en la línea de crédito.','Brand URL'=>'URL de marca','Opens in a new tab. Must start with http:// or https://.'=>'Se abre en una pestaña nueva. Debe empezar por http:// o https://.','Brand favicon'=>'Favicon de marca','Square 32×32 or larger. PNG, JPG, WebP, or SVG.'=>'Cuadrado de 32×32 o mayor. PNG, JPG, WebP o SVG.','Credit label'=>'Etiqueta de crédito','Text shown before the brand name. Leave blank for the default ("Built by").'=>'Texto que se muestra antes del nombre de marca. Déjelo en blanco para el valor predeterminado ("Creado por").','Built by'=>'Creado por','"Sign in with password" link'=>'Enlace "Iniciar sesión con contraseña"','Always-visible recovery link on every form. Only disable this if you have already disabled WordPress password authentication site-wide.'=>'Enlace de recuperación siempre visible en todos los formularios. Desactívelo solo si ya ha desactivado la autenticación por contraseña de WordPress en todo el sitio.','Per-IP window (hours)'=>'Ventana por IP (horas)','Per-IP max requests'=>'Solicitudes máximas por IP','Per-IP code window (hours)'=>'Ventana de código por IP (horas)','Per-IP max code attempts'=>'Intentos máximos de código por IP','Per-email cooldown'=>'Tiempo de espera por correo','Seconds between consecutive link requests for the same email. 0 disables. Default 60. Replaced the per-email hard cap in v1.3.7. That cap was a DoS primitive any IP could weaponize against any victim email.'=>'Segundos entre solicitudes de enlace consecutivas para el mismo correo. 0 lo desactiva. Predeterminado 60. Sustituyó al límite fijo por correo en la v1.3.7. Aquel límite era una primitiva de DoS que cualquier IP podía usar como arma contra el correo de cualquier víctima.','seconds'=>'segundos','Replace'=>'Reemplazar','Remove'=>'Eliminar','You are not allowed to do this.'=>'No tiene permiso para hacer esto.','%d outstanding token revoked.'=>'%d token pendiente revocado.' . "\0" . '%d tokens pendientes revocados.','%d throttle counter cleared.'=>'%d contador de límite borrado.' . "\0" . '%d contadores de límite borrados.','Per-user controls'=>'Controles por usuario','Disable magic-link sign-in for this user'=>'Desactivar el inicio de sesión con enlace mágico para este usuario','Saving with this checked invalidates all outstanding sign-in links for this user immediately.'=>'Guardar con esta casilla marcada invalida de inmediato todos los enlaces de acceso pendientes de este usuario.','Magic-link actions'=>'Acciones de enlace mágico','Create magic-link'=>'Crear enlace mágico','Send link to user'=>'Enviar enlace al usuario','Reset all magic-links'=>'Restablecer todos los enlaces mágicos','Cleared on next page load. Copy now.'=>'Se borra al cargar la página de nuevo. Cópielo ahora.','Could not issue link.'=>'No se pudo emitir el enlace.','Link created. Copy the URL now. It disappears on reload.'=>'Enlace creado. Copie la URL ahora. Desaparece al recargar.','wp_mail returned false. Check the server\'s mail configuration.'=>'wp_mail devolvió false. Compruebe la configuración de correo del servidor.','Link sent.'=>'Enlace enviado.','%d outstanding link reset.'=>'%d enlace pendiente restablecido.' . "\0" . '%d enlaces pendientes restablecidos.','Missing user.'=>'Falta el usuario.','User not found.'=>'Usuario no encontrado.','This sign-in link is for a different account.'=>'Este enlace de acceso es para otra cuenta.','Sign out first if you need to switch accounts.'=>'Cierre sesión primero si necesita cambiar de cuenta.','Back to site'=>'Volver al sitio','If an account exists for that email, we sent a sign-in link.'=>'Si existe una cuenta para ese correo, hemos enviado un enlace de acceso.','MagicAuth sign-in tokens'=>'Tokens de acceso de MagicAuth','Selector'=>'Selector','Issued'=>'Emitido','Expires'=>'Caduca','Consumed'=>'Consumido','not yet'=>'todavía no','%1$s is your %2$s-code'=>'%1$s es su código de %2$s','About your sign-in request for %s'=>'Sobre su solicitud de acceso para %s','Sign in'=>'Iniciar sesión','You\'re already signed in as %s.'=>'Ya ha iniciado sesión como %s.','Sign out'=>'Cerrar sesión','That reset link has expired or already been used. Request a new one below.'=>'Ese enlace de restablecimiento ha caducado o ya se ha usado. Solicite uno nuevo abajo.','That sign-in link has expired or already been used. Request a new code or link below.'=>'Ese enlace de acceso ha caducado o ya se ha usado. Solicite un nuevo código o enlace abajo.','If an account exists for that email, we sent a password reset link.'=>'Si existe una cuenta para ese correo, hemos enviado un enlace para restablecer la contraseña.','Email sent. Check your mail app.'=>'Correo enviado. Revise su aplicación de correo.','That code is invalid or has expired. Try again, or request a new code.'=>'Ese código no es válido o ha caducado. Vuelva a intentarlo o solicite un código nuevo.','Sign-in failed. Check your username and password, or use a magic link instead.'=>'El inicio de sesión falló. Compruebe su usuario y contraseña, o use un enlace mágico en su lugar.','Could not set a new password. Make sure both fields match and try again.'=>'No se pudo establecer una nueva contraseña. Asegúrese de que ambos campos coincidan e inténtelo de nuevo.','Please wait %d seconds before requesting another link for this email.'=>'Espere %d segundos antes de solicitar otro enlace para este correo.','Please wait a moment before requesting another link for this email.'=>'Espere un momento antes de solicitar otro enlace para este correo.','Too many sign-in requests from your network. Please try again later, or sign in with a password.'=>'Demasiadas solicitudes de acceso desde su red. Inténtelo más tarde o inicie sesión con una contraseña.','Too many code attempts from your network. Please request a new sign-in link.'=>'Demasiados intentos de código desde su red. Solicite un nuevo enlace de acceso.','Too many sign-in attempts. Please wait a few minutes before trying again.'=>'Demasiados intentos de acceso. Espere unos minutos antes de volver a intentarlo.','Too many password-reset requests. Please wait an hour before trying again.'=>'Demasiadas solicitudes de restablecimiento de contraseña. Espere una hora antes de volver a intentarlo.','Too many incorrect codes for this link. Please request a new sign-in link.'=>'Demasiados códigos incorrectos para este enlace. Solicite un nuevo enlace de acceso.','Dismiss'=>'Descartar','MagicAuth: response-flush helper unavailable.'=>'MagicAuth: el ayudante de vaciado de respuesta no está disponible.','Your PHP runtime does not provide fastcgi_finish_request(). MagicAuth cannot defer email sending until after the response, so SMTP latency may leak whether an account exists. Switch to PHP-FPM (or LiteSpeed) for full timing parity.'=>'Su entorno de ejecución de PHP no proporciona fastcgi_finish_request(). MagicAuth no puede aplazar el envío de correo hasta después de la respuesta, por lo que la latencia de SMTP podría revelar si una cuenta existe. Cambie a PHP-FPM (o LiteSpeed) para una paridad de tiempos completa.','MagicAuth: weak WordPress salts detected.'=>'MagicAuth: se han detectado salts débiles de WordPress.','Your security keys still hold placeholder or empty values, so token and session secrets are not unique to this site. Your magic links stay safe (each carries its own random secret), but fixing this is recommended — especially before turning on the branded login replacement.'=>'Sus claves de seguridad aún contienen valores de marcador de posición o vacíos, por lo que los secretos de token y de sesión no son únicos para este sitio. Sus enlaces mágicos siguen siendo seguros (cada uno lleva su propio secreto aleatorio), pero se recomienda corregir esto — especialmente antes de activar el reemplazo de acceso personalizado.','Learn how to fix this'=>'Aprenda a corregir esto','MagicAuth login activity'=>'Actividad de acceso de MagicAuth','Built by %s'=>'Creado por %s','A sign-in code was just requested for your account at %s.'=>'Se acaba de solicitar un código de acceso para su cuenta en %s.','Magic link and code sign-in is currently turned off for your account, so no code was sent. This is a setting managed by your site administrator and is often part of routine account changes.'=>'El inicio de sesión con enlace mágico y código está desactivado actualmente para su cuenta, por lo que no se envió ningún código. Es un ajuste gestionado por el administrador de su sitio y suele formar parte de cambios de cuenta rutinarios.','You may still be able to sign in with your password through the regular sign-in screen. If you are not sure whether your account should have access, please contact your site administrator.'=>'Es posible que aún pueda iniciar sesión con su contraseña a través de la pantalla de acceso habitual. Si no está seguro de si su cuenta debería tener acceso, póngase en contacto con el administrador de su sitio.','If you have questions about your account access, please contact your site administrator.'=>'Si tiene preguntas sobre el acceso a su cuenta, póngase en contacto con el administrador de su sitio.','If you did not request a sign-in code, you can ignore this message. No further action is needed.'=>'Si no solicitó un código de acceso, puede ignorar este mensaje. No es necesaria ninguna otra acción.','Sign in to %s'=>'Iniciar sesión en %s','Use the code below or open the sign-in link. Both expire in %d minutes.'=>'Use el código de abajo o abra el enlace de acceso. Ambos caducan en %d minutos.','Sign-in code:'=>'Código de acceso:','Sign-in link:'=>'Enlace de acceso:','If you didn\'t request this, you can safely ignore this email.'=>'Si no solicitó esto, puede ignorar este correo con tranquilidad.','(This is a test send from the MagicAuth diagnostics screen.)'=>'(Este es un envío de prueba desde la pantalla de diagnóstico de MagicAuth.)','Use the code below or click the button to sign in. Both expire in %d minutes.'=>'Use el código de abajo o haga clic en el botón para iniciar sesión. Ambos caducan en %d minutos.','Test send'=>'Envío de prueba','Check your email'=>'Revise su correo','Reset your password'=>'Restablezca su contraseña','Set a new password'=>'Establezca una nueva contraseña','Enter the verification code we sent to %s.'=>'Introduzca el código de verificación que enviamos a %s.','Enter the 6-character code we just emailed you.'=>'Introduzca el código de 6 caracteres que acabamos de enviarle por correo.','Enter your username or email and we will send a link to set a new password.'=>'Introduzca su usuario o correo y le enviaremos un enlace para establecer una nueva contraseña.','Choose a strong password. You will be signed in once it is saved.'=>'Elija una contraseña segura. Iniciará sesión una vez que se guarde.','6-character verification code'=>'Código de verificación de 6 caracteres','Use a different email'=>'Usar otro correo','Username or email'=>'Usuario o correo','Password'=>'Contraseña','Remember me'=>'Recuérdame','Forgot password?'=>'¿Olvidó su contraseña?','Use a magic link instead'=>'Usar un enlace mágico en su lugar','Send Reset Link'=>'Enviar enlace de restablecimiento','Back to sign in'=>'Volver a iniciar sesión','New password'=>'Nueva contraseña','Confirm new password'=>'Confirmar nueva contraseña','Save and sign in'=>'Guardar e iniciar sesión','Email address'=>'Dirección de correo','Send Link'=>'Enviar enlace','Sign in with password'=>'Iniciar sesión con contraseña','Change language. Current:'=>'Cambiar idioma. Actual:']];